Here's the result of running `cat -n` on a snippet of server/exotelStreamHandler.ts
     1→/**
     2→ * Exotel Bidirectional Voicebot Stream Handler
     3→ *
     4→ * Exotel sends: Connected → Start → Media (inbound audio) → Stop
     5→ * We respond with:  Media events (μ-law 8000 Hz audio chunks) + Clear to cancel current playback
     6→ *
     7→ * Audio pipeline (inbound):  μ-law 8k  →  PCM16 8k  →  upsample to 16k  →  WAV → Whisper STT
     8→ * Audio pipeline (outbound): OpenAI TTS (PCM 24k)  →  downsample to 8k  →  μ-law  →  base64 chunks
     9→ */
    10→
    11→import OpenAI from "openai";
    12→import { WebSocket } from "ws";
    13→import { log } from "./index";
    14→import { generateAIResponse, generateGreeting, type ConversationMessage, type CampaignData } from "./openaiService";
    15→import { storage } from "./storage";
    16→import { phoneCallMap, callSidMap, normalizePhone } from "./callMap";
    17→
    18→const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
    19→
    20→// --- PATCH START: Exotel stream handling safety patch ---
    21→
    22→type ExotelMediaFormat = {
    23→  encoding?: string;
    24→  sampleRate?: number | string;
    25→  sample_rate?: number | string;
    26→  channels?: number | string;
    27→};
    28→
    29→type ExotelSessionState = {
    30→  campaignId?: string;
    31→  mediaFormat: {
    32→    encoding: string;
    33→    sampleRate: number;
    34→    channels: number;
    35→  };
    36→  transcriptBuffer: string[];
    37→  audioChunks: Buffer[];
    38→  lastMediaAt: number;
    39→  isProcessing: boolean;
    40→};
    41→
    42→function safeJsonParse(input: string): any | null {
    43→  try {
    44→    return JSON.parse(input);
    45→  } catch {
    46→    return null;
    47→  }
    48→}
    49→
    50→function getEventName(payload: any): string {
    51→  return (
    52→    payload?.event ??
    53→    payload?.type ??
    54→    payload?.message_type ??
    55→    payload?.action ??
    56→    ""
    57→  )
    58→    .toString()
    59→    .trim();
    60→}
    61→
    62→function normalizeMediaFormat(raw: any): {
    63→  encoding: string;
    64→  sampleRate: number;
    65→  channels: number;
    66→} {
    67→  const mediaFormat: ExotelMediaFormat =
    68→    raw?.mediaFormat ??
    69→    raw?.media_format ??
    70→    raw?.start?.mediaFormat ??
    71→    raw?.start?.media_format ??
    72→    {};
    73→
    74→  const encoding = String(mediaFormat.encoding ?? "pcm");
    75→  const sampleRate = Number(
    76→    mediaFormat.sampleRate ?? mediaFormat.sample_rate ?? 8000
    77→  );
    78→  const channels = Number(mediaFormat.channels ?? 1);
    79→
    80→  return { encoding, sampleRate, channels };
    81→}
    82→
    83→function getMediaPayload(payload: any): string | null {
    84→  return (
    85→    payload?.media?.payload ??
    86→    payload?.media?.data ??
    87→    payload?.payload ??
    88→    payload?.data ??
    89→    null
    90→  );
    91→}
    92→
    93→// ─── G.711 μ-law Codec (pure JS — no external dependencies) ──────────────────
    94→
    95→const MULAW_BIAS = 33;
    96→const MULAW_CLIP = 32635;
    97→
    98→/** Encode one 16-bit PCM sample to a μ-law byte */
    99→export function encodeMulaw(sample: number): number {
   100→  let sign = 0;
   101→  if (sample < 0) { sign = 0x80; sample = -sample; }
   102→  if (sample > MULAW_CLIP) sample = MULAW_CLIP;
   103→  sample += MULAW_BIAS;
   104→  let exp = 7;
   105→  for (let mask = 0x4000; !(sample & mask) && exp > 0; mask >>= 1) exp--;
   106→  const mantissa = (sample >> (exp + 3)) & 0x0f;
   107→  return (~(sign | (exp << 4) | mantissa)) & 0xff;
   108→}
   109→
   110→/** Decode one μ-law byte to a 16-bit PCM sample */
   111→export function decodeMulaw(mulaw: number): number {
   112→  mulaw = ~mulaw;
   113→  const sign     = mulaw & 0x80;
   114→  const exponent = (mulaw >> 4) & 0x07;
   115→  const mantissa = mulaw & 0x0f;
   116→  let sample = ((mantissa << 3) + 132) << exponent;
   117→  sample -= 132;
   118→  return sign ? -sample : sample;
   119→}
   120→
   121→/** Buffer of μ-law bytes → Int16Array of PCM samples */
   122→export function mulawToInt16(buf: Buffer): Int16Array {
   123→  const out = new Int16Array(buf.length);
   124→  for (let i = 0; i < buf.length; i++) out[i] = decodeMulaw(buf[i]);
   125→  return out;
   126→}
   127→
   128→/** Int16Array of PCM samples → Buffer of μ-law bytes */
   129→export function int16ToMulaw(pcm: Int16Array): Buffer {
   130→  const out = Buffer.allocUnsafe(pcm.length);
   131→  for (let i = 0; i < pcm.length; i++) out[i] = encodeMulaw(pcm[i]);
   132→  return out;
   133→}
   134→
   135→// ─── PCM Resampler (linear interpolation) ────────────────────────────────────
   136→
   137→/**
   138→ * Resample PCM16 samples from srcRate to dstRate.
   139→ * Uses linear interpolation — works cleanly for integer ratio pairs (24000→8000, 8000→16000).
   140→ *
   141→ * TODO: Replace with a higher-quality resampler (e.g. libsamplerate via WASM)
   142→ *       if audio artefacts are noticeable in production calls.
   143→ */
   144→export function resamplePCM16(
   145→  samples: Int16Array,
   146→  srcRate: number,
   147→  dstRate: number
   148→): Int16Array {
   149→  if (srcRate === dstRate) return samples;
   150→  const ratio     = srcRate / dstRate;
   151→  const outLength = Math.floor(samples.length / ratio);
   152→  const out       = new Int16Array(outLength);
   153→  for (let i = 0; i < outLength; i++) {
   154→    const pos  = i * ratio;
   155→    const lo   = Math.floor(pos);
   156→    const hi   = Math.min(lo + 1, samples.length - 1);
   157→    const frac = pos - lo;
   158→    out[i]     = Math.round(samples[lo] * (1 - frac) + samples[hi] * frac);
   159→  }
   160→  return out;
   161→}
   162→
   163→// ─── WAV Builder ──────────────────────────────────────────────────────────────
   164→
   165→/** Wrap raw PCM16 samples in a minimal WAV container (required by Whisper) */
   166→export function buildWav(pcm: Int16Array, sampleRate: number, channels = 1): Buffer {
   167→  const dataBytes = pcm.length * 2;
   168→  const buf       = Buffer.allocUnsafe(44 + dataBytes);
   169→  buf.write("RIFF", 0);
   170→  buf.writeUInt32LE(36 + dataBytes, 4);
   171→  buf.write("WAVE", 8);
   172→  buf.write("fmt ", 12);
   173→  buf.writeUInt32LE(16, 16);
   174→  buf.writeUInt16LE(1, 20);                          // PCM
   175→  buf.writeUInt16LE(channels, 22);
   176→  buf.writeUInt32LE(sampleRate, 24);
   177→  buf.writeUInt32LE(sampleRate * channels * 2, 28);  // ByteRate
   178→  buf.writeUInt16LE(channels * 2, 32);               // BlockAlign
   179→  buf.writeUInt16LE(16, 34);                         // BitsPerSample
   180→  buf.write("data", 36);
   181→  buf.writeUInt32LE(dataBytes, 40);
   182→  for (let i = 0; i < pcm.length; i++) buf.writeInt16LE(pcm[i], 44 + i * 2);
   183→  return buf;
   184→}
   185→
   186→// ─── STT: Transcription ───────────────────────────────────────────────────────
   187→
   188→/**
   189→ * Transcribe accumulated μ-law audio (8 kHz mono) to text using OpenAI Whisper.
   190→ *
   191→ * TODO: Swap this function with a different STT provider (e.g. Deepgram, Google STT)
   192→ *       by replacing the implementation while keeping the same signature:
   193→ *         transcribeAudio(mulawChunks: Buffer[]): Promise<string>
   194→ */
   195→export async function transcribeAudio(mulawChunks: Buffer[]): Promise<string> {
   196→  if (mulawChunks.length === 0) return "";
   197→
   198→  const raw = Buffer.concat(mulawChunks);
   199→  if (raw.length < 160) return ""; // less than 20 ms — treat as silence
   200→
   201→  // PCM16 LE 8 kHz (Exotel sends raw slin16) → PCM16 16 kHz (Whisper prefers ≥16 kHz)
   202→  const pcm8k  = new Int16Array(raw.buffer, raw.byteOffset, raw.byteLength / 2);
   203→  const pcm16k = resamplePCM16(pcm8k, 8000, 16000);
   204→  const wav    = buildWav(pcm16k, 16000);
   205→
   206→  // Whisper needs a File-like object
   207→  const { toFile } = await import("openai");
   208→  const wavFile = await toFile(wav, "audio.wav", { type: "audio/wav" });
   209→
   210→  const result = await openai.audio.transcriptions.create({
   211→    model:    "whisper-1",
   212→    file:     wavFile,
   213→    language: "en",
   214→  });
   215→
   216→  return result.text.trim();
   217→}
   218→
   219→// ─── TTS: Exotel-compatible audio encoding ────────────────────────────────────
   220→
   221→/**
   222→ * 20 ms of audio at 8 kHz = 160 μ-law bytes per chunk.
   223→ * Exotel's Media payload should carry one chunk at a time for smooth streaming.
   224→ * 320 bytes (40 ms) is also acceptable and reduces WebSocket message overhead.
   225→ *
   226→ * TODO: If TTS audio quality is unacceptable at 8 kHz, replace `openaiTTS` below
   227→ *       with a provider that outputs PCMU/8000 natively, e.g.:
   228→ *         - Google Cloud TTS telephony preset  (LINEAR16 or MULAW @ 8000 Hz)
   229→ *         - ElevenLabs streaming with ULAW_8000 output format
   230→ *         - Deepgram Aura (outputs μ-law on request)
   231→ */
   232→const EXOTEL_SAMPLE_RATE = 8000;
   233→const EXOTEL_CHUNK_BYTES = 3200; // 100 ms of PCM16 LE @ 8 kHz = 3200 bytes (Exotel requires multiples of 320)
   234→
   235→/**
   236→ * Convert AI reply text → array of base64-encoded PCM16 LE chunks ready for Exotel Media events.
   237→ * Pipeline: OpenAI TTS (raw PCM 24 kHz) → downsample to 8 kHz PCM16 LE → split into 3200-byte chunks
   238→ * Exotel expects Linear PCM16 LE @ 8 kHz, base64-encoded, in multiples of 320 bytes.
   239→ */
   240→export async function encodeReplyForExotel(text: string): Promise<string[]> {
   241→  // Request raw PCM from OpenAI TTS (24 kHz, 16-bit LE mono, no container)
   242→  const response = await openai.audio.speech.create({
   243→    model:           "tts-1",
   244→    voice:           "nova",
   245→    input:           text,
   246→    response_format: "pcm",
   247→  });
   248→
   249→  const raw    = Buffer.from(await response.arrayBuffer());
   250→  const pcm24k = new Int16Array(raw.buffer, raw.byteOffset, raw.byteLength / 2);
   251→  const pcm8k  = resamplePCM16(pcm24k, 24000, EXOTEL_SAMPLE_RATE);
   252→
   253→  // Convert Int16Array → raw PCM16 LE Buffer (no μ-law encoding — Exotel expects PCM16)
   254→  const pcm8kBuf = Buffer.from(pcm8k.buffer, pcm8k.byteOffset, pcm8k.byteLength);
   255→
   256→  // Split into 3200-byte chunks (100 ms @ 8 kHz PCM16) and base64-encode each
   257→  const chunks: string[] = [];
   258→  for (let off = 0; off < pcm8kBuf.length; off += EXOTEL_CHUNK_BYTES) {
   259→    chunks.push(pcm8kBuf.slice(off, off + EXOTEL_CHUNK_BYTES).toString("base64"));
   260→  }
   261→  return chunks;
   262→}
   263→
   264→// ─── Exotel WebSocket Send Helpers ───────────────────────────────────────────
   265→
   266→/** Send one μ-law audio chunk back to Exotel as a Media event */
   267→export function sendExotelMedia(
   268→  ws: WebSocket,
   269→  streamSid: string,
   270→  payload: string
   271→): void {
   272→  if (ws.readyState !== WebSocket.OPEN) return;
   273→
   274→  const message = {
   275→    event: "media",
   276→    stream_sid: streamSid,
   277→    media: {
   278→      payload,
   279→    },
   280→  };
   281→
   282→  console.log("[EXOTEL OUTGOING]", JSON.stringify(message));
   283→
   284→  ws.send(JSON.stringify(message));
   285→}
   286→
   287→/** Tell Exotel to immediately stop playing any buffered audio */
   288→export function sendExotelClear(ws: WebSocket, streamSid: string): void {
   289→  if (ws.readyState !== WebSocket.OPEN) return;
   290→  ws.send(JSON.stringify({ event: "clear", stream_sid: streamSid }));
   291→}
   292→
   293→// ─── Campaign Loader ──────────────────────────────────────────────────────────
   294→
   295→/** Load campaign from DB by ID, fall back to first available if not found */
   296→export async function loadCampaignData(campaignId?: string): Promise<CampaignData> {
   297→  let campaign: any = campaignId ? await storage.getCampaign(campaignId) : null;
   298→  if (!campaign)    campaign = await storage.getAnyCampaign();
   299→  if (!campaign)    return { goal: "sales" };
   300→
   301→  return {
   302→    name:                campaign.name,
   303→    goal:                campaign.goal,
   304→    additionalContext:   campaign.additionalContext   || "",
   305→    ai_generated_script: campaign.ai_generated_script || campaign.script || "",
   306→    knowledge_base: [
   307→      ...(campaign.knowledgeBaseTexts || []),
   308→      ...(campaign.knowledgeBaseFiles || []).map((f: any) => f.extractedText).filter(Boolean),
   309→    ].join("\n\n"),
   310→  };
   311→}
   312→
   313→// ─── Per-connection Session ───────────────────────────────────────────────────
   314→
   315→interface ExotelSession {
   316→  streamSid:           string;
   317→  campaignId?:         string;
   318→  mediaChunks:         Buffer[];
   319→  conversationHistory: ConversationMessage[];
   320→  silenceTimer:        ReturnType<typeof setTimeout> | null;
   321→  forceTimer:          ReturnType<typeof setTimeout> | null;
   322→  firstChunkAt:        number | null;
   323→  processing:          boolean;
   324→  isSpeaking:          boolean;   // true while AI TTS is being sent — suppress echo
   325→  bargeInCount:        number;    // consecutive high-energy chunks during AI speech
   326→  voicedChunks:        number;    // voiced chunks seen in current utterance
   327→}
   328→
   329→// ── VAD & timing constants ────────────────────────────────────────────────────
   330→
   331→// How long silence after voiced speech before triggering STT (ms).
   332→// 1500 ms gives natural pause space without cutting the caller mid-sentence.
   333→const SILENCE_TIMEOUT_MS = 1500;
   334→
   335→// Absolute fallback: process whatever was collected this many ms after first chunk.
   336→// Large value (8 s) lets callers finish full sentences before force-processing.
   337→const FORCE_PROCESS_MS = 8000;
   338→
   339→// RMS energy below this → silence / background noise (flat PCM).
   340→const VAD_THRESHOLD = 200;
   341→
   342→// Minimum consecutive voiced chunks before the silence timer starts.
   343→// Prevents a single noise pop from triggering a processing cycle.
   344→const MIN_VOICED_BEFORE_TIMER = 2;
   345→
   346→// ── Barge-in constants ────────────────────────────────────────────────────────
   347→
   348→// RMS threshold to consider caller is speaking while AI is talking.
   349→// Higher than VAD_THRESHOLD to avoid false positives from echo/noise.
   350→const BARGE_IN_THRESHOLD = 700;
   351→
   352→// How many consecutive high-energy chunks must arrive before we accept a barge-in.
   353→// 3 chunks × ~100 ms/chunk ≈ 300 ms of sustained speech.
   354→const BARGE_IN_MIN_CHUNKS = 3;
   355→
   356→// ── Filler acknowledgments ────────────────────────────────────────────────────
   357→
   358→// Two sets: one for when the caller asks a question, one for statements.
   359→// Chosen by whether the transcribed text ends with "?".
   360→// Keeps fillers contextually appropriate and avoids the jarring mismatch of
   361→// saying "Sure." before completely ignoring what the caller asked.
   362→const FILLER_QUESTION  = ["Let me check on that.", "Good question.", "Let me look into that."];
   363→const FILLER_STATEMENT = ["I hear you.", "Understood.", "Got it.", "I see.", "Good to know."];
   364→
   365→/** Calculate RMS energy of a PCM16 LE buffer — used for voice activity detection */
   366→function rmsLevel(buf: Buffer): number {
   367→  if (buf.length < 2) return 0;
   368→  let sumSq = 0;
   369→  for (let i = 0; i + 1 < buf.length; i += 2) {
   370→    const sample = buf.readInt16LE(i);
   371→    sumSq += sample * sample;
   372→  }
   373→  return Math.sqrt(sumSq / (buf.length / 2));
   374→}
   375→
   376→/** Reset all per-turn state after AI finishes speaking */
   377→function resetTurn(session: ExotelSession): void {
   378→  session.isSpeaking   = false;
   379→  session.bargeInCount = 0;
   380→  session.voicedChunks = 0;
   381→  session.mediaChunks  = [];
   382→  session.firstChunkAt = null;
   383→  if (session.silenceTimer) { clearTimeout(session.silenceTimer); session.silenceTimer = null; }
   384→  if (session.forceTimer)   { clearTimeout(session.forceTimer);   session.forceTimer   = null; }
   385→}
   386→
   387→async function processAudio(ws: WebSocket, session: ExotelSession): Promise<void> {
   388→  if (session.processing || session.mediaChunks.length === 0) return;
   389→  session.processing = true;
   390→
   391→  const chunks     = session.mediaChunks.splice(0);
   392→  const totalBytes = chunks.reduce((s, b) => s + b.length, 0);
   393→  log(`[exotel:${session.streamSid}] ▶ processAudio — ${chunks.length} chunks, ${totalBytes} B`, "ws");
   394→
   395→  try {
   396→    // ── Step 1: Transcribe caller audio (Whisper) ─────────────────────────────
   397→    const userText = await transcribeAudio(chunks);
   398→    log(`[exotel:${session.streamSid}] ▶ STT: "${userText}"`, "ws");
   399→    if (!userText) {
   400→      log(`[exotel:${session.streamSid}] ▶ Empty STT — skipping`, "ws");
   401→      return;
   402→    }
   403→
   404→    // ── Step 2: Parallel — filler TTS + GPT response ─────────────────────────
   405→    // Start both simultaneously so the caller hears a filler phrase (~0.5 s)
   406→    // while GPT generates the actual response (~1–2 s).
   407→    const campaignData = await loadCampaignData(session.campaignId);
   408→    session.conversationHistory.push({ role: "user", content: userText });
   409→
   410→    const filler = FILLER_PHRASES[Math.floor(Math.random() * FILLER_PHRASES.length)];
   411→
   412→    // Fire both API calls at the same time
   413→    const fillerTtsPromise   = encodeReplyForExotel(filler);
   414→    const aiResponsePromise  = generateAIResponse(
   415→      session.conversationHistory,
   416→      userText,
   417→      campaignData
   418→    );
   419→
   420→    // ── Step 3: Play filler as soon as its TTS is ready ───────────────────────
   421→    const fillerChunks = await fillerTtsPromise;
   422→    session.isSpeaking = true;
   423→    sendExotelClear(ws, session.streamSid);
   424→    for (const chunk of fillerChunks) {
   425→      if (ws.readyState !== WebSocket.OPEN) break;
   426→      sendExotelMedia(ws, session.streamSid, chunk);
   427→    }
   428→    log(`[exotel:${session.streamSid}] ▶ Filler sent: "${filler}"`, "ws");
   429→
   430→    // ── Step 4: Await GPT result (usually ready by now) ───────────────────────
   431→    const { reply } = await aiResponsePromise;
   432→    session.conversationHistory.push({ role: "assistant", content: reply });
   433→    log(`[exotel:${session.streamSid}] ▶ AI: "${reply}"`, "ws");
   434→
   435→    // ── Step 5: TTS for actual response, then stream it ───────────────────────
   436→    const responseChunks = await encodeReplyForExotel(reply);
   437→    log(`[exotel:${session.streamSid}] ▶ TTS ready — ${responseChunks.length} chunks`, "ws");
   438→
   439→    for (const chunk of responseChunks) {
   440→      if (ws.readyState !== WebSocket.OPEN) break;
   441→      // If barge-in happened while we were waiting for TTS, abort sending
   442→      if (!session.isSpeaking) {
   443→        log(`[exotel:${session.streamSid}] ▶ Barge-in interrupted response`, "ws");
   444→        break;
   445→      }
   446→      sendExotelMedia(ws, session.streamSid, chunk);
   447→    }
   448→    log(`[exotel:${session.streamSid}] ▶ Response sent`, "ws");
   449→
   450→  } catch (err: any) {
   451→    log(`[exotel:${session.streamSid}] ✖ processAudio error: ${err.message}`, "ws");
   452→  } finally {
   453→    resetTurn(session);
   454→    session.processing = false;
   455→  }
   456→}
   457→
   458→// ─── Greeting ─────────────────────────────────────────────────────────────────
   459→
   460→/**
   461→ * Speak the opening greeting immediately when the call connects.
   462→ * Fired once from the "start" event handler (fire-and-forget via setTimeout).
   463→ */
   464→async function sendGreeting(ws: WebSocket, session: ExotelSession): Promise<void> {
   465→  if (session.isSpeaking || session.processing) return;
   466→  try {
   467→    const campaignData = await loadCampaignData(session.campaignId);
   468→    const greeting     = await generateGreeting(campaignData);
   469→
   470→    log(`[exotel:${session.streamSid}] ▶ Greeting: "${greeting}"`, "ws");
   471→
   472→    session.isSpeaking = true;
   473→    const chunks = await encodeReplyForExotel(greeting);
   474→    for (const chunk of chunks) {
   475→      if (ws.readyState !== WebSocket.OPEN) break;
   476→      sendExotelMedia(ws, session.streamSid, chunk);
   477→    }
   478→    // Add greeting to history so AI knows not to repeat it
   479→    session.conversationHistory.push({ role: "assistant", content: greeting });
   480→    log(`[exotel:${session.streamSid}] ▶ Greeting sent (${chunks.length} chunks)`, "ws");
   481→  } catch (err: any) {
   482→    log(`[exotel] Greeting error: ${err?.message ?? err}`, "ws");
   483→  } finally {
   484→    // Full reset: clears timers, buffers, and speaking state so any audio the
   485→    // caller said before/during the greeting doesn't leak into the first turn.
   486→    resetTurn(session);
   487→  }
   488→}
   489→
   490→// ─── Main Handler ─────────────────────────────────────────────────────────────
   491→
   492→/**
   493→ * Handle the full lifecycle of one Exotel bidirectional voicebot stream.
   494→ * Wire this to the /exotel-stream WebSocket path in wsServer.ts.
   495→ *
   496→ * Uses safe JSON parsing and defensive mediaFormat extraction so a missing
   497→ * or differently-shaped Start payload never crashes the handler.
   498→ *
   499→ * @param ws                The raw WebSocket connection from Exotel
   500→ * @param initialCampaignId Optional — pulled from URL query param ?campaignId=...
   501→ */
   502→export async function handleExotelStream(
   503→  ws: any,
   504→  initialCampaignId?: string
   505→): Promise<void> {
   506→  const session: ExotelSession = {
   507→    streamSid:           "",
   508→    campaignId:          initialCampaignId,
   509→    mediaChunks:         [],
   510→    conversationHistory: [],
   511→    silenceTimer:        null,
   512→    forceTimer:          null,
   513→    firstChunkAt:        null,
   514→    processing:          false,
   515→    isSpeaking:          false,
   516→    bargeInCount:        0,
   517→    voicedChunks:        0,
   518→  };
   519→
   520→  log(`[exotel] session started campaignId=${session.campaignId ?? "none"}`, "ws");
   521→
   522→  ws.on("message", async (raw: Buffer | string) => {
   523→    const rawText = Buffer.isBuffer(raw) ? raw.toString("utf8") : String(raw);
