   365→/** Calculate RMS energy of a PCM16 LE buffer — used for voice activity detection */
   366→function rmsLevel(buf: Buffer): number {
   367→  if (buf.length < 2) return 0;
   368→  let sumSq = 0;
   369→  for (let i = 0; i + 1 < buf.length; i += 2) {
   370→    const sample = buf.readInt16LE(i);
   371→    sumSq += sample * sample;
   372→  }
   373→  return Math.sqrt(sumSq / (buf.length / 2));
   374→}
