export async function makeExotelCall(toNumber: string): Promise<ExotelCallResult> {
  console.log("Calling number:", toNumber);

  const url = `https://api.exotel.com/v1/Accounts/${EXOTEL_SID}/Calls/connect`;

  // Build the public base URL — prefer explicit PUBLIC_URL, then Replit dev domain, then production fallback
  const publicBase =
    process.env.PUBLIC_URL ||
    (process.env.REPLIT_DEV_DOMAIN ? `https://${process.env.REPLIT_DEV_DOMAIN}` : null) ||
    "https://nijvox.com";

  // When the customer answers, Exotel fetches this URL to get ExoML instructions.
  // Our /exotel/voice endpoint returns a bidirectional Stream pointing to our WebSocket.
  const voiceWebhookUrl = `${publicBase}/exotel/voice`;
  console.log("[Exotel] Voice webhook URL:", voiceWebhookUrl);

  const params = new URLSearchParams();
  params.append("From",     toNumber);       // Customer number to be called
  params.append("CallerId", EXOTEL_PHONE);   // Exophone shown to customer
  params.append("Url",      voiceWebhookUrl); // Our dynamic ExoML voice webhook

