    22→  message: string;
    23→  timestamp: string;
    24→}
    25→
    26→// ─── Helpers ─────────────────────────────────────────────────────────────────
    27→
    28→/**
    29→ * Parse a raw WebSocket message into a structured StreamEvent.
    30→ * Handles both JSON objects and plain text strings.
    31→ */
    32→export function parseStreamEvent(raw: string): StreamEvent | null {
    33→  try {
    34→    const parsed = JSON.parse(raw);
    35→    return {
    36→      type:       parsed.type       ?? "text",
    37→      payload:    parsed.payload    ?? parsed,
    38→      timestamp:  parsed.timestamp  ?? new Date().toISOString(),
    39→      message:    typeof parsed.message === "string" ? parsed.message : undefined,
    40→      campaignId: typeof parsed.campaignId === "string" ? parsed.campaignId : undefined,
    41→    };
    42→  } catch {
    43→    // Plain text — treat as a user text message
    44→    return {
    45→      type:      "text",
    46→      payload:   raw,
    47→      timestamp: new Date().toISOString(),
    48→      message:   raw,
    49→    };
    50→  }
    51→}
    52→
    53→/**
    54→ * Send a structured text response back to a WebSocket client.
    55→ * No-ops silently if the socket is not open.
    56→ */
    57→export function sendTextResponse(ws: WebSocket, message: string): void {
    58→  if (ws.readyState !== WebSocket.OPEN) return;
    59→
    60→  const response: TextResponse = {
    61→    type:      "text",
    62→    message,
    63→    timestamp: new Date().toISOString(),
    64→  };
    65→
    66→  ws.send(JSON.stringify(response));
    67→}
    68→
    69→/**
    70→ * Convert text to speech and send the audio back through the WebSocket.
    71→ * Sends: { type: "audio", mimeType: "audio/mpeg", audioBase64: "...", timestamp }
    72→ */
    73→async function sendAudioResponse(ws: WebSocket, text: string, voice?: string): Promise<void> {
    74→  if (ws.readyState !== WebSocket.OPEN) return;
    75→
    76→  const { audioBase64, mimeType } = await textToSpeech(text, voice);
    77→
    78→  ws.send(JSON.stringify({
    79→    type:        "audio",
    80→    mimeType,
    81→    audioBase64,
    82→    timestamp:   new Date().toISOString(),
    83→  }));
    84→}
    85→
    86→// ─── AI Reply ────────────────────────────────────────────────────────────────
    87→
    88→/**
    89→ * Fetch campaign from DB and call OpenAI to generate a short conversational reply.
    90→ * Falls back to the first available campaign if no campaignId is given.
    91→ */
    92→async function getAIReply(
    93→  userText: string,
    94→  campaignId: string | undefined,
    95→  history: ConversationMessage[]
    96→): Promise<string> {
    97→  // Fetch campaign data
    98→  let campaign: any = null;
    99→  if (campaignId) {
   100→    campaign = await storage.getCampaign(campaignId);
   101→  }
   102→  if (!campaign) {
   103→    campaign = await storage.getAnyCampaign();
   104→  }
   105→
   106→  // Build campaignData object for generateAIResponse
   107→  const campaignData: CampaignData = campaign
   108→    ? {
   109→        name:               campaign.name,
   110→        goal:               campaign.goal,
   111→        additionalContext:  campaign.additionalContext || "",
   112→        ai_generated_script: campaign.ai_generated_script || campaign.script || "",
   113→        knowledge_base: [
   114→          ...(campaign.knowledgeBaseTexts || []),
   115→          ...(campaign.knowledgeBaseFiles || [])
   116→            .map((f: any) => f.extractedText)
   117→            .filter(Boolean),
   118→        ].join("\n\n"),
   119→      }
   120→    : { goal: "sales" };
   121→
   122→  const result = await generateAIResponse(history, userText, campaignData);
   123→  return result.reply;
   124→}
   125→
   126→// ─── /stream connection handler ──────────────────────────────────────────────
   127→
   128→function attachStreamHandlers(wss: WebSocketServer, ws: WebSocket, clientIp: string): void {
   129→  const conversationHistory: ConversationMessage[] = [];
   130→
   131→  sendTextResponse(ws, "Connected to NIJVOX AI stream. Send a message to begin.");
   132→
   133→  ws.on("message", async (data) => {
   134→    const raw   = data.toString();
   135→    const event = parseStreamEvent(raw);
   136→
   137→    if (!event) {
   138→      log(`Unparseable message from [${clientIp}]: ${raw}`, "ws");
   139→      return;
   140→    }
   141→
   142→    const userText: string =
   143→      event.message ||
   144→      (typeof event.payload === "string" ? event.payload : JSON.stringify(event.payload));
   145→
   146→    log(`[${clientIp}] type=${event.type} campaignId=${event.campaignId ?? "none"} text="${userText}"`, "ws");
   147→
   148→    conversationHistory.push({ role: "user", content: userText });
   149→
   150→    try {
   151→      const aiReply = await getAIReply(userText, event.campaignId, conversationHistory);
   152→      conversationHistory.push({ role: "assistant", content: aiReply });
   153→
   154→      log(`[${clientIp}] AI reply: "${aiReply}"`, "ws");
   155→      sendTextResponse(ws, aiReply);
   156→
   157→      try {
   158→        await sendAudioResponse(ws, aiReply);
   159→        log(`[${clientIp}] Audio sent for reply`, "ws");
   160→      } catch (ttsErr: any) {
   161→        log(`[${clientIp}] TTS error (text reply already sent): ${ttsErr.message}`, "ws");
   162→      }
   163→    } catch (err: any) {
   164→      log(`[${clientIp}] AI error: ${err.message}`, "ws");
   165→      sendTextResponse(ws, "Sorry, I ran into an issue. Please try again.");
   166→    }
   167→  });
   168→
   169→  ws.on("close", (code, reason) => {
   170→    log(`Client disconnected [${clientIp}] code=${code} reason=${reason || "none"}  total=${wss.clients.size}`, "ws");
   171→  });
   172→
   173→  ws.on("error", (err) => {
   174→    log(`Error from [${clientIp}]: ${err.message}`, "ws");
   175→  });
   176→}
   177→
   178→// ─── Unified WebSocket setup (noServer routing) ───────────────────────────────
   179→//
   180→// Why noServer: the ws library's path-based filtering calls socket.destroy() on
   181→// any upgrade it doesn't own, so a second WebSocketServer on the same httpServer
   182→// would never receive its upgrade events.  Instead we create both servers with
   183→// noServer:true and route upgrades ourselves — unrecognised paths are left alone
   184→// so Vite HMR and other protocols can still handle them.
   185→
   186→/**
   187→ * Attach all WebSocket servers to the existing HTTP server.
   188→ *
   189→ * Paths:
   190→ *   /stream        — text + MP3 audio, for web clients and debugging
   191→ *   /exotel-stream — μ-law 8 kHz bidirectional voicebot stream for Exotel
   192→ *                    optional query param: ?campaignId=<id>
   193→ */
   194→export function setupWebSocketServer(httpServer: Server): void {
   195→  // /stream — text + MP3 debug path
   196→  const streamWss = new WebSocketServer({ noServer: true });
   197→  streamWss.on("connection", (ws, req) => {
   198→    const clientIp = req.socket.remoteAddress ?? "unknown";
   199→    log(`[/stream] Client connected [${clientIp}]  total=${streamWss.clients.size}`, "ws");
   200→    attachStreamHandlers(streamWss, ws, clientIp);
   201→  });
   202→
   203→  // /exotel-stream — Exotel voicebot path
   204→  const exotelWss = new WebSocketServer({ noServer: true });
   205→  exotelWss.on("connection", (ws, req) => {
   206→    const clientIp = req.socket.remoteAddress ?? "unknown";
   207→    let campaignId: string | undefined;
   208→    try {
   209→      const url  = new URL(req.url ?? "", `ws://${req.headers.host}`);
   210→      campaignId = url.searchParams.get("campaignId") ?? undefined;
   211→    } catch { /* ignore */ }
   212→
   213→    log(`[/exotel-stream] Connection from [${clientIp}] campaignId=${campaignId ?? "none"}  total=${exotelWss.clients.size}`, "ws");
   214→    handleExotelStream(ws, campaignId);
   215→  });
   216→
   217→  // Single upgrade router — routes by pathname, passes unknown paths through
   218→  httpServer.on("upgrade", (req, socket, head) => {
   219→    let pathname = "/";
   220→    try {
   221→      pathname = new URL(req.url ?? "", `ws://${req.headers.host}`).pathname;
   222→    } catch { /* ignore */ }
   223→
   224→    if (pathname === "/stream") {
   225→      streamWss.handleUpgrade(req, socket as any, head, (ws) => {
   226→        streamWss.emit("connection", ws, req);
   227→      });
   228→    } else if (pathname === "/exotel-stream") {
   229→      exotelWss.handleUpgrade(req, socket as any, head, (ws) => {
   230→        exotelWss.emit("connection", ws, req);
   231→      });
   232→    }
   233→    // All other paths (e.g. Vite HMR) are left untouched
   234→  });
   235→
   236→  log("WebSocket server ready on path /stream", "ws");
   237→  log("Exotel voicebot stream ready on path /exotel-stream", "ws");
   238→}
