// Step 2: Place the outbound call.
//
// Exotel's Calls/connect requires a proper two-leg structure for the Url
// parameter to be honoured.  The standard way to make an outbound call
// with ExoML is via the base /Calls endpoint (Twilio-compatible):
//   From = Exophone  (the number that shows up to the customer)
//   To   = Customer  (who gets called)
//   Url  = ExoML URL (fetched when To answers)
//
// Without a To party, Calls/connect ignores Url and falls back to the
// Exophone's dashboard-configured app — which has a stale stream URL.
const callUrl      = `https://api.exotel.com/v1/Accounts/${EXOTEL_SID}/Calls`;
const publicBase   = getPublicBase();
const voiceHookUrl = `${publicBase}/exotel/voice`;

const params = new URLSearchParams();
params.append("From",     EXOTEL_PHONE); // Exophone — shown as caller to customer
params.append("To",       toNumber);     // Customer number to be called
params.append("Url",      voiceHookUrl); // Our ExoML endpoint (fetched when To answers)

console.log("FROM (Exophone) =", EXOTEL_PHONE);
console.log("TO   (Customer) =", toNumber);
console.log("[Exotel] Voice hook URL:", voiceHookUrl);
console.log("[Exotel] Expected WSS  :", wssUrl);

