    93→// ─── G.711 μ-law Codec (pure JS — no external dependencies) ──────────────────
    94→
    95→const MULAW_BIAS = 33;
    96→const MULAW_CLIP = 32635;
    97→
    98→/** Encode one 16-bit PCM sample to a μ-law byte */
    99→export function encodeMulaw(sample: number): number {
   100→  let sign = 0;
   101→  if (sample < 0) { sign = 0x80; sample = -sample; }
   102→  if (sample > MULAW_CLIP) sample = MULAW_CLIP;
   103→  sample += MULAW_BIAS;
   104→  let exp = 7;
   105→  for (let mask = 0x4000; !(sample & mask) && exp > 0; mask >>= 1) exp--;
   106→  const mantissa = (sample >> (exp + 3)) & 0x0f;
   107→  return (~(sign | (exp << 4) | mantissa)) & 0xff;
   108→}
   109→
   110→/** Decode one μ-law byte to a 16-bit PCM sample */
   111→export function decodeMulaw(mulaw: number): number {
   112→  mulaw = ~mulaw;
   113→  const sign     = mulaw & 0x80;
   114→  const exponent = (mulaw >> 4) & 0x07;
   115→  const mantissa = mulaw & 0x0f;
   116→  let sample = ((mantissa << 3) + 132) << exponent;
   117→  sample -= 132;
   118→  return sign ? -sample : sample;
   119→}
   120→
   121→/** Buffer of μ-law bytes → Int16Array of PCM samples */
   122→export function mulawToInt16(buf: Buffer): Int16Array {
   123→  const out = new Int16Array(buf.length);
   124→  for (let i = 0; i < buf.length; i++) out[i] = decodeMulaw(buf[i]);
   125→  return out;
   126→}
   127→
   128→/** Int16Array of PCM samples → Buffer of μ-law bytes */
   129→export function int16ToMulaw(pcm: Int16Array): Buffer {
   130→  const out = Buffer.allocUnsafe(pcm.length);
   131→  for (let i = 0; i < pcm.length; i++) out[i] = encodeMulaw(pcm[i]);
   132→  return out;
   133→}
   134→
   135→// ─── PCM Resampler (linear interpolation) ────────────────────────────────────
   136→
   137→/**
   138→ * Resample PCM16 samples from srcRate to dstRate.
   139→ * Uses linear interpolation — works cleanly for integer ratio pairs (24000→8000, 8000→16000).
   140→ *
   141→ * TODO: Replace with a higher-quality resampler (e.g. libsamplerate via WASM)
   142→ *       if audio artefacts are noticeable in production calls.
   143→ */
   144→export function resamplePCM16(
   145→  samples: Int16Array,
   146→  srcRate: number,
   147→  dstRate: number
   148→): Int16Array {
   149→  if (srcRate === dstRate) return samples;
   150→  const ratio     = srcRate / dstRate;
   151→  const outLength = Math.floor(samples.length / ratio);
   152→  const out       = new Int16Array(outLength);
   153→  for (let i = 0; i < outLength; i++) {
   154→    const pos  = i * ratio;
   155→    const lo   = Math.floor(pos);
   156→    const hi   = Math.min(lo + 1, samples.length - 1);
   157→    const frac = pos - lo;
   158→    out[i]     = Math.round(samples[lo] * (1 - frac) + samples[hi] * frac);
   159→  }
   160→  return out;
   161→}
   162→
   163→// ─── WAV Builder ──────────────────────────────────────────────────────────────
   164→
   165→/** Wrap raw PCM16 samples in a minimal WAV container (required by Whisper) */
   166→export function buildWav(pcm: Int16Array, sampleRate: number, channels = 1): Buffer {
   167→  const dataBytes = pcm.length * 2;
   168→  const buf       = Buffer.allocUnsafe(44 + dataBytes);
   169→  buf.write("RIFF", 0);
   170→  buf.writeUInt32LE(36 + dataBytes, 4);
   171→  buf.write("WAVE", 8);
   172→  buf.write("fmt ", 12);
   173→  buf.writeUInt32LE(16, 16);
   174→  buf.writeUInt16LE(1, 20);                          // PCM
   175→  buf.writeUInt16LE(channels, 22);
   176→  buf.writeUInt32LE(sampleRate, 24);
   177→  buf.writeUInt32LE(sampleRate * channels * 2, 28);  // ByteRate
   178→  buf.writeUInt16LE(channels * 2, 32);               // BlockAlign
   179→  buf.writeUInt16LE(16, 34);                         // BitsPerSample
   180→  buf.write("data", 36);
   181→  buf.writeUInt32LE(dataBytes, 40);
   182→  for (let i = 0; i < pcm.length; i++) buf.writeInt16LE(pcm[i], 44 + i * 2);
   183→  return buf;
   184→}
   185→
   186→// ─── STT: Transcription ───────────────────────────────────────────────────────
   187→
   188→/**
   189→ * Transcribe accumulated μ-law audio (8 kHz mono) to text using OpenAI Whisper.
   190→ *
   191→ * TODO: Swap this function with a different STT provider (e.g. Deepgram, Google STT)
   192→ *       by replacing the implementation while keeping the same signature:
   193→ *         transcribeAudio(mulawChunks: Buffer[]): Promise<string>
   194→ */
   195→export async function transcribeAudio(mulawChunks: Buffer[]): Promise<string> {
   196→  if (mulawChunks.length === 0) return "";
   197→
   198→  const raw = Buffer.concat(mulawChunks);
   199→  if (raw.length < 160) return ""; // less than 20 ms — treat as silence
   200→
   201→  // PCM16 LE 8 kHz (Exotel sends raw slin16) → PCM16 16 kHz (Whisper prefers ≥16 kHz)
   202→  const pcm8k  = new Int16Array(raw.buffer, raw.byteOffset, raw.byteLength / 2);
   203→  const pcm16k = resamplePCM16(pcm8k, 8000, 16000);
   204→  const wav    = buildWav(pcm16k, 16000);
   205→
   206→  // Whisper needs a File-like object
   207→  const { toFile } = await import("openai");
   208→  const wavFile = await toFile(wav, "audio.wav", { type: "audio/wav" });
   209→
   210→  const result = await openai.audio.transcriptions.create({
   211→    model:    "whisper-1",
   212→    file:     wavFile,
   213→    language: "en",
   214→  });
   215→
   216→  return result.text.trim();
   217→}
   218→
   219→// ─── TTS: Exotel-compatible audio encoding ────────────────────────────────────
   220→
   221→/**
   222→ * 20 ms of audio at 8 kHz = 160 μ-law bytes per chunk.
   223→ * Exotel's Media payload should carry one chunk at a time for smooth streaming.
   224→ * 320 bytes (40 ms) is also acceptable and reduces WebSocket message overhead.
   225→ *
   226→ * TODO: If TTS audio quality is unacceptable at 8 kHz, replace `openaiTTS` below
   227→ *       with a provider that outputs PCMU/8000 natively, e.g.:
   228→ *         - Google Cloud TTS telephony preset  (LINEAR16 or MULAW @ 8000 Hz)
   229→ *         - ElevenLabs streaming with ULAW_8000 output format
   230→ *         - Deepgram Aura (outputs μ-law on request)
   231→ */
   232→const EXOTEL_SAMPLE_RATE = 8000;
   233→const EXOTEL_CHUNK_BYTES = 3200; // 100 ms of PCM16 LE @ 8 kHz = 3200 bytes (Exotel requires multiples of 320)
   234→
   235→/**
   236→ * Convert AI reply text → array of base64-encoded PCM16 LE chunks ready for Exotel Media events.
   237→ * Pipeline: OpenAI TTS (raw PCM 24 kHz) → downsample to 8 kHz PCM16 LE → split into 3200-byte chunks
   238→ * Exotel expects Linear PCM16 LE @ 8 kHz, base64-encoded, in multiples of 320 bytes.
   239→ */
   240→export async function encodeReplyForExotel(text: string): Promise<string[]> {
   241→  // Request raw PCM from OpenAI TTS (24 kHz, 16-bit LE mono, no container)
   242→  const response = await openai.audio.speech.create({
   243→    model:           "tts-1",
   244→    voice:           "nova",
   245→    input:           text,
   246→    response_format: "pcm",
   247→  });
   248→
   249→  const raw    = Buffer.from(await response.arrayBuffer());
   250→  const pcm24k = new Int16Array(raw.buffer, raw.byteOffset, raw.byteLength / 2);
   251→  const pcm8k  = resamplePCM16(pcm24k, 24000, EXOTEL_SAMPLE_RATE);
   252→
   253→  // Convert Int16Array → raw PCM16 LE Buffer (no μ-law encoding — Exotel expects PCM16)
   254→  const pcm8kBuf = Buffer.from(pcm8k.buffer, pcm8k.byteOffset, pcm8k.byteLength);
   255→
   256→  // Split into 3200-byte chunks (100 ms @ 8 kHz PCM16) and base64-encode each
   257→  const chunks: string[] = [];
   258→  for (let off = 0; off < pcm8kBuf.length; off += EXOTEL_CHUNK_BYTES) {
   259→    chunks.push(pcm8kBuf.slice(off, off + EXOTEL_CHUNK_BYTES).toString("base64"));
   260→  }
   261→  return chunks;
   262→}
