   313→// ─── Per-connection Session ───────────────────────────────────────────────────
   314→
   315→interface ExotelSession {
   316→  streamSid:           string;
   317→  campaignId?:         string;
   318→  mediaChunks:         Buffer[];
   319→  conversationHistory: ConversationMessage[];
   320→  silenceTimer:        ReturnType<typeof setTimeout> | null;
   321→  forceTimer:          ReturnType<typeof setTimeout> | null;
   322→  firstChunkAt:        number | null;
   323→  processing:          boolean;
   324→  isSpeaking:          boolean;   // true while AI TTS is being sent — suppress echo
   325→  bargeInCount:        number;    // consecutive high-energy chunks during AI speech
   326→  voicedChunks:        number;    // voiced chunks seen in current utterance
   327→}
   328→
   329→// ── VAD & timing constants ────────────────────────────────────────────────────
   330→
   331→// How long silence after voiced speech before triggering STT (ms).
   332→// 1500 ms gives natural pause space without cutting the caller mid-sentence.
   333→const SILENCE_TIMEOUT_MS = 1500;
   334→
   335→// Absolute fallback: process whatever was collected this many ms after first chunk.
   336→// Large value (8 s) lets callers finish full sentences before force-processing.
   337→const FORCE_PROCESS_MS = 8000;
   338→
   339→// RMS energy below this → silence / background noise (flat PCM).
   340→const VAD_THRESHOLD = 200;
   341→
   342→// Minimum consecutive voiced chunks before the silence timer starts.
   343→// Prevents a single noise pop from triggering a processing cycle.
   344→const MIN_VOICED_BEFORE_TIMER = 2;
   345→
   346→// ── Barge-in constants ────────────────────────────────────────────────────────
   347→
   348→// RMS threshold to consider caller is speaking while AI is talking.
   349→// Higher than VAD_THRESHOLD to avoid false positives from echo/noise.
   350→const BARGE_IN_THRESHOLD = 700;
   351→
   352→// How many consecutive high-energy chunks must arrive before we accept a barge-in.
   353→// 3 chunks × ~100 ms/chunk ≈ 300 ms of sustained speech.
   354→const BARGE_IN_MIN_CHUNKS = 3;
   355→
   356→// ── Filler acknowledgments ────────────────────────────────────────────────────
   357→
   358→// Two sets: one for when the caller asks a question, one for statements.
   359→// Chosen by whether the transcribed text ends with "?".
   360→// Keeps fillers contextually appropriate and avoids the jarring mismatch of
   361→// saying "Sure." before completely ignoring what the caller asked.
   362→const FILLER_QUESTION  = ["Let me check on that.", "Good question.", "Let me look into that."];
   363→const FILLER_STATEMENT = ["I hear you.", "Understood.", "Got it.", "I see.", "Good to know."];
   364→
   365→/** Calculate RMS energy of a PCM16 LE buffer — used for voice activity detection */
   366→function rmsLevel(buf: Buffer): number {
   367→  if (buf.length < 2) return 0;
   368→  let sumSq = 0;
   369→  for (let i = 0; i + 1 < buf.length; i += 2) {
   370→    const sample = buf.readInt16LE(i);
   371→    sumSq += sample * sample;
   372→  }
   373→  return Math.sqrt(sumSq / (buf.length / 2));
   374→}
   375→
   376→/** Reset all per-turn state after AI finishes speaking */
   377→function resetTurn(session: ExotelSession): void {
   378→  session.isSpeaking   = false;
   379→  session.bargeInCount = 0;
   380→  session.voicedChunks = 0;
   381→  session.mediaChunks  = [];
   382→  session.firstChunkAt = null;
   383→  if (session.silenceTimer) { clearTimeout(session.silenceTimer); session.silenceTimer = null; }
   384→  if (session.forceTimer)   { clearTimeout(session.forceTimer);   session.forceTimer   = null; }
   385→}
   386→
   387→async function processAudio(ws: WebSocket, session: ExotelSession): Promise<void> {
   388→  if (session.processing || session.mediaChunks.length === 0) return;
   389→  session.processing = true;
   390→
   391→  const chunks     = session.mediaChunks.splice(0);
   392→  const totalBytes = chunks.reduce((s, b) => s + b.length, 0);
   393→  log(`[exotel:${session.streamSid}] ▶ processAudio — ${chunks.length} chunks, ${totalBytes} B`, "ws");
   394→
   395→  try {
   396→    // ── Step 1: Transcribe caller audio (Whisper) ─────────────────────────────
   397→    const userText = await transcribeAudio(chunks);
   398→    log(`[exotel:${session.streamSid}] ▶ STT: "${userText}"`, "ws");
   399→    if (!userText) {
   400→      log(`[exotel:${session.streamSid}] ▶ Empty STT — skipping`, "ws");
   401→      return;
   402→    }
   403→
   404→    // ── Step 2: Parallel — filler TTS + GPT response ─────────────────────────
   405→    // Start both simultaneously so the caller hears a filler phrase (~0.5 s)
   406→    // while GPT generates the actual response (~1–2 s).
   407→    const campaignData = await loadCampaignData(session.campaignId);
   408→    session.conversationHistory.push({ role: "user", content: userText });
   409→
   410→    const fillerPool = userText.trim().endsWith("?") ? FILLER_QUESTION : FILLER_STATEMENT;
   411→    const filler = fillerPool[Math.floor(Math.random() * fillerPool.length)];
   412→
   413→    // Fire both API calls at the same time
   414→    const fillerTtsPromise   = encodeReplyForExotel(filler);
   415→    const aiResponsePromise  = generateAIResponse(
   416→      session.conversationHistory,
   417→      userText,
   418→      campaignData
   419→    );
   420→
   421→    // ── Step 3: Play filler as soon as its TTS is ready ───────────────────────
   422→    const fillerChunks = await fillerTtsPromise;
   423→    session.isSpeaking = true;
   424→    sendExotelClear(ws, session.streamSid);
   425→    for (const chunk of fillerChunks) {
   426→      if (ws.readyState !== WebSocket.OPEN) break;
   427→      sendExotelMedia(ws, session.streamSid, chunk);
   428→    }
   429→    log(`[exotel:${session.streamSid}] ▶ Filler sent: "${filler}"`, "ws");
   430→
   431→    // ── Step 4: Await GPT result (usually ready by now) ───────────────────────
   432→    const { reply } = await aiResponsePromise;
   433→    session.conversationHistory.push({ role: "assistant", content: reply });
   434→    log(`[exotel:${session.streamSid}] ▶ AI: "${reply}"`, "ws");
   435→
   436→    // ── Step 5: TTS for actual response, then stream it ───────────────────────
   437→    const responseChunks = await encodeReplyForExotel(reply);
   438→    log(`[exotel:${session.streamSid}] ▶ TTS ready — ${responseChunks.length} chunks`, "ws");
   439→
   440→    for (const chunk of responseChunks) {
   441→      if (ws.readyState !== WebSocket.OPEN) break;
   442→      // If barge-in happened while we were waiting for TTS, abort sending
   443→      if (!session.isSpeaking) {
   444→        log(`[exotel:${session.streamSid}] ▶ Barge-in interrupted response`, "ws");
   445→        break;
   446→      }
   447→      sendExotelMedia(ws, session.streamSid, chunk);
   448→    }
   449→    log(`[exotel:${session.streamSid}] ▶ Response sent`, "ws");
   450→
   451→  } catch (err: any) {
   452→    log(`[exotel:${session.streamSid}] ✖ processAudio error: ${err.message}`, "ws");
   453→  } finally {
   454→    resetTurn(session);
   455→    session.processing = false;
   456→  }
   457→}
   458→
   459→// ─── Greeting ─────────────────────────────────────────────────────────────────
   460→
   461→/**
   462→ * Speak the opening greeting immediately when the call connects.
   463→ * Fired once from the "start" event handler (fire-and-forget via setTimeout).
   464→ */
   465→async function sendGreeting(ws: WebSocket, session: ExotelSession): Promise<void> {
   466→  if (session.isSpeaking || session.processing) return;
   467→  try {
   468→    const campaignData = await loadCampaignData(session.campaignId);
   469→    const greeting     = await generateGreeting(campaignData);
   470→
   471→    log(`[exotel:${session.streamSid}] ▶ Greeting: "${greeting}"`, "ws");
   472→
   473→    session.isSpeaking = true;
   474→    const chunks = await encodeReplyForExotel(greeting);
   475→    for (const chunk of chunks) {
   476→      if (ws.readyState !== WebSocket.OPEN) break;
   477→      sendExotelMedia(ws, session.streamSid, chunk);
   478→    }
   479→    // Add greeting to history so AI knows not to repeat it
   480→    session.conversationHistory.push({ role: "assistant", content: greeting });
   481→    log(`[exotel:${session.streamSid}] ▶ Greeting sent (${chunks.length} chunks)`, "ws");
   482→  } catch (err: any) {
   483→    log(`[exotel] Greeting error: ${err?.message ?? err}`, "ws");
   484→  } finally {
   485→    // Full reset: clears timers, buffers, and speaking state so any audio the
   486→    // caller said before/during the greeting doesn't leak into the first turn.
   487→    resetTurn(session);
   488→  }
   489→}
   490→
   491→// ─── Main Handler ─────────────────────────────────────────────────────────────
   492→
   493→/**
   494→ * Handle the full lifecycle of one Exotel bidirectional voicebot stream.
   495→ * Wire this to the /exotel-stream WebSocket path in wsServer.ts.
   496→ *
   497→ * Uses safe JSON parsing and defensive mediaFormat extraction so a missing
   498→ * or differently-shaped Start payload never crashes the handler.
   499→ *
   500→ * @param ws                The raw WebSocket connection from Exotel
   501→ * @param initialCampaignId Optional — pulled from URL query param ?campaignId=...
   502→ */
   503→export async function handleExotelStream(
   504→  ws: any,
   505→  initialCampaignId?: string
   506→): Promise<void> {
   507→  const session: ExotelSession = {
   508→    streamSid:           "",
   509→    campaignId:          initialCampaignId,
   510→    mediaChunks:         [],
   511→    conversationHistory: [],
   512→    silenceTimer:        null,
   513→    forceTimer:          null,
   514→    firstChunkAt:        null,
   515→    processing:          false,
   516→    isSpeaking:          false,
   517→    bargeInCount:        0,
   518→    voicedChunks:        0,
   519→  };
   520→
   521→  log(`[exotel] session started campaignId=${session.campaignId ?? "none"}`, "ws");
   522→
   523→  ws.on("message", async (raw: Buffer | string) => {
   524→    const rawText = Buffer.isBuffer(raw) ? raw.toString("utf8") : String(raw);
   525→
   526→    // Safe parse — never crash on non-JSON (plain text, empty frames, etc.)
   527→    const payload = safeJsonParse(rawText);
   528→    if (!payload) {
   529→      log("[exotel] non-JSON message ignored", "ws");
   530→      return;
   531→    }
   532→
   533→    // Flexible event name — works with event / type / message_type / action fields
   534→    const eventName = getEventName(payload).toLowerCase();
   535→
   536→    // Log all non-media events in full; media events get a compact log below
   537→    if (eventName !== "media") {
   538→      log(`[exotel] raw message: ${rawText}`, "ws");
   539→    }
   540→
   541→    try {
   542→      switch (eventName) {
