import OpenAI from "openai";

const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
});

export interface CallScriptInput {
  campaignGoal: string;
  existingScript?: string;
  additionalContext?: string;
  campaignName?: string;
  knowledgeBaseText?: string;
}

export interface GeneratedScript {
  script: string;
}

export async function generateCallScript(input: CallScriptInput): Promise<GeneratedScript> {
  const { campaignGoal, existingScript, additionalContext, campaignName, knowledgeBaseText } = input;

  const systemPrompt = `You are an expert AI calling script writer. Your job is to create professional, natural-sounding phone call scripts for AI agents.

Guidelines:
- Write in a conversational, friendly tone
- Include personalization placeholders like {name} and {company} where appropriate
- Keep the opening concise and engaging
- Match the tone to the campaign goal
- Structure the script with a clear opening, value proposition, and call-to-action
- Make it sound human and empathetic, not robotic
- If knowledge base content is provided, use it to tailor the script with accurate product/service details
- Keep it under 200 words for the main script`;

  const userPrompt = `Create a professional AI calling script for the following campaign:

Campaign Name: ${campaignName || "Unnamed Campaign"}
Campaign Goal: ${campaignGoal}
${existingScript ? `Existing Script (improve upon this): ${existingScript}` : ""}
${additionalContext ? `Additional Context/Business Information: ${additionalContext}` : ""}
${knowledgeBaseText ? `Knowledge Base (use this for accurate product/service details):\n${knowledgeBaseText.slice(0, 3000)}` : ""}

Return ONLY the call script text, ready to use. Include personalization variables like {name} where appropriate. Do not include any explanations or headers.`;

  const response = await openai.chat.completions.create({
    model: "gpt-4o",
    messages: [
      { role: "system", content: systemPrompt },
      { role: "user", content: userPrompt },
    ],
    temperature: 0.7,
    max_tokens: 500,
  });

  const script = response.choices[0]?.message?.content?.trim() || "";

  return { script };
}

export interface ConversationMessage {
  role: "user" | "assistant";
  content: string;
}

export interface LeadData {
  name?: string;
  company?: string;
  phone?: string;
  email?: string;
  [key: string]: string | undefined;
}

export interface CampaignData {
  name?: string;
  goal: string;
  script?: string;
  additionalContext?: string;
  knowledgeBaseText?: string;
  ai_generated_script?: string;
  knowledge_base?: string;
  leadData?: LeadData;
}

export interface AIResponse {
  reply: string;
}

function replaceScriptVariables(text: string, lead: LeadData): string {
  return text.replace(/\{(\w+)\}/g, (match, key) => {
    const value = lead[key as keyof LeadData];
    return value !== undefined && value !== "" ? value : match;
  });
}

/**
 * Generate a professional opening greeting for when the call connects.
 * Introduces the agent by name, states the company, and smoothly opens the conversation.
 */
export async function generateGreeting(campaignData: CampaignData): Promise<string> {
  const { name, goal, ai_generated_script, additionalContext } = campaignData;

  const isSupport = (goal || "").toLowerCase().includes("support");

  const response = await openai.chat.completions.create({
    model: "gpt-4o",
    messages: [
      {
        role: "system",
        content: `You are writing the opening line for an AI phone agent making an outbound call.

Rules:
- Sound like a real human professional, NOT a robot
- Introduce as "this is [Agent Name]" — pick a natural first name like Sarah, Alex, or James
- Mention the campaign/company name if provided
- State the reason for the call in ONE natural sentence
- End with a soft, open question like "Is now a good time?" or "Do you have a couple of minutes?"
- Maximum 2 short spoken sentences total
- No filler words, no "um", no "uh"
- Output ONLY the spoken greeting text, nothing else`,
      },
      {
        role: "user",
        content: `Campaign name: ${name || ""}
Goal: ${goal}
Context: ${additionalContext || ""}
Type: ${isSupport ? "customer support" : "outbound sales"}`,
      },
    ],
    max_tokens: 80,
    temperature: 0.5,
  });

  return (
    response.choices[0]?.message?.content?.trim() ||
    `Hello, this is Alex calling. I'm reaching out about a quick opportunity — do you have a moment?`
  );
}

/**
 * Generate a conversational AI reply during a live phone call.
 * Handles the full conversation arc: open → discover → pitch → handle objections → close.
 */
export async function generateAIResponse(
  conversationHistory: ConversationMessage[],
  userInput: string,
  campaignData: CampaignData
): Promise<AIResponse> {
  const { name, goal, additionalContext, ai_generated_script, knowledge_base, knowledgeBaseText, leadData } = campaignData;

  const resolvedScript = ai_generated_script && leadData
    ? replaceScriptVariables(ai_generated_script, leadData)
    : (ai_generated_script || "");

  const knowledgeBaseContent = knowledge_base || knowledgeBaseText || "";
  const isSupport = (goal || "").toLowerCase().includes("support");
  const turnCount = conversationHistory.length;

  const systemPrompt = `You are a professional AI ${isSupport ? "customer support representative" : "sales representative"} on a LIVE outbound phone call.
${name ? `\nCampaign: ${name}` : ""}
Goal: ${goal}
${additionalContext ? `\nAbout the business: ${additionalContext}` : ""}
${resolvedScript ? `\nCall guide (use as inspiration, NOT word-for-word):\n${resolvedScript}` : ""}
${knowledgeBaseContent ? `\nKnowledge base:\n${knowledgeBaseContent.slice(0, 2000)}` : ""}

SPEAKING RULES — follow these strictly:
1. You are speaking out loud on a phone call. Every word will be read aloud by a voice synthesizer.
2. Keep replies to 1–2 SHORT spoken sentences maximum. No long explanations.
3. Speak naturally and confidently — like a seasoned professional, not a chatbot.
4. Do NOT ask a question every single turn. Ask one only when it moves the conversation forward.
5. Do NOT repeat anything already said in this conversation.
6. No bullet points, no lists, no formatting, no asterisks — plain spoken language only.
7. Vary your tone: affirm, inform, ask, respond — don't follow a rigid script.
8. If the person sounds busy or hesitant: acknowledge it warmly, offer to call back at a better time.
9. If they ask something off-topic: answer briefly and steer back to the purpose of the call.
10. Handle objections calmly and confidently with a brief reframe, then move on.
11. Never say "Great!", "Absolutely!", "Certainly!" as a reflex opener — it sounds robotic. Start with the substance.
12. Mirror the caller's energy: if they're brief, be brief; if they're chatty, be a bit warmer.
${turnCount <= 2 ? "\n13. EARLY IN CALL: Focus on qualifying — find out if this is the right person and time." : ""}
${turnCount >= 6 ? "\n13. LATER IN CALL: Move toward a clear next step, offer, or close." : ""}`;

  const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
    { role: "system", content: systemPrompt },
    ...conversationHistory.map(m => ({
      role: m.role as "user" | "assistant",
      content: m.content,
    })),
    { role: "user", content: userInput },
  ];

  const response = await openai.chat.completions.create({
    model: "gpt-4o-mini",
    messages,
    temperature: 0.65,
    max_tokens: 90,
  });

  const reply = response.choices[0]?.message?.content?.trim() || "";
  return { reply };
}

export async function generateTextResponse(prompt: string): Promise<string> {
  const response = await openai.chat.completions.create({
    model: "gpt-4o",
    messages: [{ role: "user", content: prompt }],
    temperature: 0.7,
    max_tokens: 1000,
  });

  return response.choices[0]?.message?.content?.trim() || "";
}

export async function testOpenAI(): Promise<string> {
  const response = await openai.chat.completions.create({
    model: "gpt-4o",
    messages: [{ role: "user", content: "Say exactly: Hello from AI" }],
    max_tokens: 20,
  });

  return response.choices[0]?.message?.content?.trim() || "No response";
}

