arguments.new_string:
/**
 * Generate a professional opening greeting for when the call connects.
 *
 * CRITICAL RULES:
 * - ONLY introduce yourself and ask if now is a good time. Nothing else.
 * - Do NOT mention the product, price, offer, or anything about why you're calling.
 * - That comes AFTER they confirm it's a good time.
 * - Maximum 1–2 short sentences. Under 10 seconds when spoken.
 */
export async function generateGreeting(campaignData: CampaignData): Promise<string> {
  const { name, goal, additionalContext } = campaignData;

  // Derive a clean company/context name from additionalContext or goal
  // (don't use raw campaign name which might be "Real Estate Campaign Course" etc.)
  const contextHint = additionalContext
    ? additionalContext.slice(0, 200)
    : `a ${goal} company`;

  const response = await openai.chat.completions.create({
    model: "gpt-4o",
    messages: [
      {
        role: "system",
        content: `You are writing the OPENING LINE ONLY for an AI phone agent on an outbound call.

STRICT RULES:
- Pick a natural agent first name (Sarah, James, Priya, Alex, etc.)
- Introduce yourself: "Hi, this is [Name] calling."
- Ask ONE soft permission question: "Is this a good time for a quick chat?" or "Do you have 2 minutes?"
- Do NOT mention the product, price, discount, location, or ANY details about why you're calling
- Do NOT say "I appreciate your time" or other clichés
- Do NOT use the raw campaign name as the company name — derive a natural company/brand name from the context
- Maximum 2 short sentences. This must take under 8 seconds to speak aloud.
- Output ONLY the greeting text, nothing else`,
      },
      {
        role: "user",
        content: `Business context: ${contextHint}
Goal: ${goal}`,
      },
    ],
    max_tokens: 60,
    temperature: 0.4,
  });

  return (
    response.choices[0]?.message?.content?.trim() ||
    `Hi, this is Sarah calling. Do you have a couple of minutes?`
  );
}

