import OpenAI from "openai";

const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
});

export interface CallScriptInput {
  campaignGoal: string;
  existingScript?: string;
  additionalContext?: string;
  campaignName?: string;
  knowledgeBaseText?: string;
}

export interface GeneratedScript {
  script: string;
}

export async function generateCallScript(input: CallScriptInput): Promise<GeneratedScript> {
  const { campaignGoal, existingScript, additionalContext, campaignName, knowledgeBaseText } = input;

  const systemPrompt = `You are an expert AI calling script writer. Your job is to create professional, natural-sounding phone call scripts for AI agents.

Guidelines:
- Write in a conversational, friendly tone
- Include personalization placeholders like {name} and {company} where appropriate
- Keep the opening concise and engaging
- Match the tone to the campaign goal
- Structure the script with a clear opening, value proposition, and call-to-action
- Make it sound human and empathetic, not robotic
- If knowledge base content is provided, use it to tailor the script with accurate product/service details
- Keep it under 200 words for the main script`;

  const userPrompt = `Create a professional AI calling script for the following campaign:

Campaign Name: ${campaignName || "Unnamed Campaign"}
Campaign Goal: ${campaignGoal}
${existingScript ? `Existing Script (improve upon this): ${existingScript}` : ""}
${additionalContext ? `Additional Context/Business Information: ${additionalContext}` : ""}
${knowledgeBaseText ? `Knowledge Base (use this for accurate product/service details):\n${knowledgeBaseText.slice(0, 3000)}` : ""}

Return ONLY the call script text, ready to use. Include personalization variables like {name} where appropriate. Do not include any explanations or headers.`;

  const response = await openai.chat.completions.create({
    model: "gpt-4o",
    messages: [
      { role: "system", content: systemPrompt },
      { role: "user", content: userPrompt },
    ],
    temperature: 0.7,
    max_tokens: 500,
  });

  const script = response.choices[0]?.message?.content?.trim() || "";
  return { script };
}

export interface ConversationMessage {
  role: "user" | "assistant";
  content: string;
}

export interface LeadData {
  name?: string;
  company?: string;
  phone?: string;
  email?: string;
  [key: string]: string | undefined;
}

export interface CampaignData {
  name?: string;
  goal: string;
  script?: string;
  additionalContext?: string;
  knowledgeBaseText?: string;
  ai_generated_script?: string;
  knowledge_base?: string;
  leadData?: LeadData;
}

export interface AIResponse {
  reply: string;
}

function replaceScriptVariables(text: string, lead: LeadData): string {
  return text.replace(/\{(\w+)\}/g, (match, key) => {
    const value = lead[key as keyof LeadData];
    return value !== undefined && value !== "" ? value : match;
  });
}

/**
 * Short, permission-seeking greeting ONLY.
 * Does NOT mention product, price, location, or anything about why we're calling.
 * That all comes after the user says yes.
 */
export async function generateGreeting(campaignData: CampaignData): Promise<string> {
  const { goal } = campaignData;
  const isSupport = (goal || "").toLowerCase().includes("support");

  const response = await openai.chat.completions.create({
    model: "gpt-4o",
    messages: [
      {
        role: "system",
        content: `Write the single opening line spoken by an AI phone agent at the very start of an outbound call.

HARD RULES — violating any of these is a failure:
- ONE sentence: introduce yourself with a first name, then ask permission. Nothing else.
- Do NOT mention the product, service, price, location, discount, reason for calling, or company name.
- Do NOT say more than one sentence.
- Do NOT say "I appreciate your time", "I hope you're doing well", or any filler cliché.
- Examples of CORRECT output:
    "Hi, this is James — do you have a quick minute?"
    "Hey, this is Sarah calling — is now a good time?"
    "Hi, this is Alex — got a moment to chat?"
- Examples of WRONG output (too much info):
    "Hi, this is Priya calling from XYZ Homes about the apartments you enquired about."
    "Hi, this is Alex — I'm calling about an exciting real estate opportunity."
- Output ONLY the spoken sentence. No quotes, no explanation.`,
      },
      {
        role: "user",
        content: `Call type: ${isSupport ? "customer support" : "outbound sales"}`,
      },
    ],
    max_tokens: 40,
    temperature: 0.3,
  });

  return (
    response.choices[0]?.message?.content?.trim() ||
    "Hi, this is Sarah — do you have a quick minute?"
  );
}

/**
 * Generate a conversational AI reply during a live phone call.
 * Uses gpt-4o for high-quality, contextually accurate responses.
 */
export async function generateAIResponse(
  conversationHistory: ConversationMessage[],
  userInput: string,
  campaignData: CampaignData
): Promise<AIResponse> {
  const { name, goal, additionalContext, ai_generated_script, knowledge_base, knowledgeBaseText, leadData } = campaignData;

  const resolvedScript = ai_generated_script && leadData
    ? replaceScriptVariables(ai_generated_script, leadData)
    : (ai_generated_script || "");

  const knowledgeBaseContent = knowledge_base || knowledgeBaseText || "";
  const isSupport = (goal || "").toLowerCase().includes("support");
  const turnCount = conversationHistory.length;

  // Detect high-value moments in the conversation
  const userLower = userInput.toLowerCase();
  const wantsToSchedule = /schedul|book|visit|appointment|meet|monday|tuesday|wednesday|thursday|friday|saturday|sunday|\d+\s*(am|pm)/i.test(userInput);
  const wantsDetails = /tell me more|more about|details|how much|price|cost|location|ameniti|size|bhk|bedroom|floor/i.test(userLower);
  const isAffirmative = /^(yes|yeah|yep|sure|ok|okay|go ahead|please|yea|mhm|of course|absolutely|definitely|fine|alright)[\s.!,]*$/i.test(userInput.trim());

  const systemPrompt = `You are a professional AI ${isSupport ? "customer support agent" : "sales agent"} on a LIVE phone call. You represent this business.

${name ? `Campaign: ${name}` : ""}
Goal: ${goal}
${additionalContext ? `Business info: ${additionalContext}` : ""}
${resolvedScript ? `Call script / talking points:\n${resolvedScript}` : ""}
${knowledgeBaseContent ? `Knowledge base:\n${knowledgeBaseContent.slice(0, 2000)}` : ""}

━━━ SPEAKING RULES (read every rule before responding) ━━━

FORMAT:
• Spoken words only — no bullet points, no lists, no formatting, no asterisks.
• Maximum 2 SHORT sentences. Aim for 1.
• Do NOT start with filler words like "Great!", "Absolutely!", "Certainly!", "Of course!".

CONVERSATION ACCURACY — these failures have happened before, avoid them:
• NEVER say "You're welcome" unless the person said "thank you".
• NEVER say "It seems like there might be a mix-up" or question your own purpose mid-call.
• NEVER re-introduce yourself after the first turn — you already introduced yourself in the greeting.
• NEVER say "I'm here to help, let me know if you have questions" — that gives zero information. Actually answer.
• When the person says "Yes" or "Sure" in response to your question, give them the information you just offered — don't ask another question or say anything irrelevant.

SCHEDULING:
• If the caller wants to schedule a visit, meeting, or appointment: confirm their preferred time enthusiastically, ask for their name if you don't already have it, and say you'll arrange it. This is a HIGH-PRIORITY OUTCOME.

CALL STAGE (turn ${turnCount}):
${turnCount <= 1 ? "• STAGE: Just got permission. Briefly explain who you are and why you're calling. Keep it to 1–2 sentences." : ""}
${turnCount >= 2 && turnCount <= 5 ? "• STAGE: Discovery & pitch. Answer their questions with specific details. Give concrete facts." : ""}
${turnCount >= 6 ? "• STAGE: Closing. Drive toward a specific next step: schedule a visit, send brochure, arrange callback." : ""}
${wantsToSchedule ? "\n⚡ ACTION REQUIRED: They want to schedule. Confirm the time they mentioned, ask for their name, and commit to the appointment." : ""}
${wantsDetails ? "\n⚡ They want details. Give 2–3 specific facts from the knowledge base/script right now." : ""}
${isAffirmative ? "\n⚡ They said yes to your last offer/question. Immediately deliver what you offered — don't ask again." : ""}`;

  const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
    { role: "system", content: systemPrompt },
    ...conversationHistory.map(m => ({
      role: m.role as "user" | "assistant",
      content: m.content,
    })),
    { role: "user", content: userInput },
  ];

  const response = await openai.chat.completions.create({
    model: "gpt-4o",          // upgraded from gpt-4o-mini — quality over cost for live calls
    messages,
    temperature: 0.3,          // low temp = consistent, contextually accurate, less hallucination
    max_tokens: 100,
  });

  const reply = response.choices[0]?.message?.content?.trim() || "";
  return { reply };
}

export async function generateTextResponse(prompt: string): Promise<string> {
  const response = await openai.chat.completions.create({
    model: "gpt-4o",
    messages: [{ role: "user", content: prompt }],
    temperature: 0.7,
    max_tokens: 1000,
  });

  return response.choices[0]?.message?.content?.trim() || "";
}

export async function testOpenAI(): Promise<string> {
  const response = await openai.chat.completions.create({
    model: "gpt-4o",
    messages: [{ role: "user", content: "Say exactly: Hello from AI" }],
    max_tokens: 20,
  });

  return response.choices[0]?.message?.content?.trim() || "No response";
}
